use proptest::prelude::*;

const MAX_MEMBERS: u8 = 32;

#[derive(Debug, Clone, Copy)]
struct State {
    threshold: u8,
    member_count: u8,
    approval_count: u8,
}

/// Proptest strategy for generating arbitrary State values.
fn arb_state() -> impl Strategy<Value = State> {
    (
        0u8..=255u8,
        0u8..=255u8,
        0u8..=255u8,
    ).prop_map(|(threshold, member_count, approval_count)| State {
        threshold,
        member_count,
        approval_count,
    })
}

/// Boundary-biased strategy for guard rejection tests.
fn arb_boundary_state() -> impl Strategy<Value = State> {
    (
        prop_oneof![0u8..=3u8, 252u8..=255u8],
        prop_oneof![0u8..=3u8, 252u8..=255u8],
        prop_oneof![0u8..=3u8, 252u8..=255u8],
    ).prop_map(|(threshold, member_count, approval_count)| State {
        threshold,
        member_count,
        approval_count,
    })
}

/// threshold_bounded: s.threshold ≤ s.member_count ∧ s.threshold > 0
fn threshold_bounded(s: &State) -> bool {
    s.threshold <= s.member_count && s.threshold > 0
}

/// approvals_bounded: s.approval_count ≤ s.member_count
fn approvals_bounded(s: &State) -> bool {
    s.approval_count <= s.member_count
}

/// Create a new multisig vault with members and approval threshold
fn create_vault(s: &mut State, threshold: u8, member_count: u8) -> bool {
    if !(threshold > 0 && threshold <= member_count && member_count <= 32) {
        return false;
    }
    s.threshold = threshold;
    s.member_count = member_count;
    s.approval_count = 0;
    true
}

/// Submit a new transaction proposal — any vault member can propose
fn propose(s: &mut State) -> bool {
    s.approval_count = 0;
    true
}

/// Approve the current proposal — each member may approve once
fn approve(s: &mut State, member_index: u8) -> bool {
    if !(member_index < s.member_count && s.approval_count < s.member_count) {
        return false;
    }
    s.approval_count = s.approval_count.wrapping_add(1);
    true
}

/// Execute the proposal once the approval threshold is met
fn execute(s: &mut State) -> bool {
    if !(s.approval_count >= s.threshold) {
        return false;
    }
    s.approval_count = 0;
    true
}

/// Cancel the current proposal and return to accepting new proposals
fn cancel_proposal(s: &mut State) -> bool {
    s.approval_count = 0;
    true
}

/// Remove a member from the vault — creator only
fn remove_member(s: &mut State) -> bool {
    if !(s.member_count > s.threshold && s.approval_count == 0) {
        return false;
    }
    s.member_count = s.member_count.wrapping_sub(1);
    true
}

proptest! {
    #![proptest_config(ProptestConfig { max_global_rejects: 65536, ..ProptestConfig::with_cases(256) })]
    #[test]
    fn create_vault_preserves_threshold_bounded(threshold in 0u8..=u8::MAX, member_count in 0u8..=u8::MAX) {
        let mut s = State {
            threshold: 0,
            member_count: 0,
            approval_count: 0,
        };
        if create_vault(&mut s, threshold, member_count) {
            prop_assert!(threshold_bounded(&s),
                "threshold_bounded must hold after create_vault");
        }
    }
}

