#[derive(Debug, Clone)]
enum Op {
    CreateVault(u8, u8),
    Propose,
    Approve(u8),
    Execute,
    CancelProposal,
    RemoveMember,
}

fn arb_op() -> impl Strategy<Value = Op> {
    prop_oneof![
        (0u8..=u8::MAX, 0u8..=u8::MAX).prop_map(|(threshold, member_count)| Op::CreateVault(threshold, member_count)),
        Just(Op::Propose),
        (0u8..=u8::MAX).prop_map(|v| Op::Approve(v)),
        Just(Op::Execute),
        Just(Op::CancelProposal),
        Just(Op::RemoveMember),
    ]
}

fn apply_op(s: &mut State, op: &Op) -> bool {
    match op {
        Op::CreateVault(threshold, member_count) => create_vault(s, *threshold, *member_count),
        Op::Propose => propose(s),
        Op::Approve(member_index) => approve(s, *member_index),
        Op::Execute => execute(s),
        Op::CancelProposal => cancel_proposal(s),
        Op::RemoveMember => remove_member(s),
    }
}

fn assert_all_properties(s: &State, context: &str) {
    assert!(threshold_bounded(s), "{} violated: threshold_bounded", context);
    assert!(approvals_bounded(s), "{} violated: approvals_bounded", context);
}

#[derive(Debug, Clone, Copy, PartialEq)]
enum Lifecycle {
    Uninitialized,
    Active,
    HasProposal,
}

fn lifecycle_transition(current: Lifecycle, op: &Op) -> Option<Lifecycle> {
    match (current, op) {
        (Lifecycle::Uninitialized, Op::CreateVault(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::Propose) => Some(Lifecycle::HasProposal),
        (Lifecycle::HasProposal, Op::Approve(..)) => Some(Lifecycle::HasProposal),
        (Lifecycle::HasProposal, Op::Execute) => Some(Lifecycle::Active),
        (Lifecycle::HasProposal, Op::CancelProposal) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::RemoveMember) => Some(Lifecycle::Active),
        _ => None, // transition not allowed in this state
    }
}

proptest! {
    #![proptest_config(ProptestConfig::with_cases(256))]
    #[test]
    fn state_machine_sequence(ops in proptest::collection::vec(arb_op(), 1..20)) {
        let mut s = State {
            threshold: 0,
            member_count: 0,
            approval_count: 0,
        };
        let mut lifecycle = Lifecycle::Uninitialized;
        let mut initialized = false;
        for (i, op) in ops.iter().enumerate() {
            let next_lifecycle = lifecycle_transition(lifecycle, op);
            if next_lifecycle.is_none() {
                continue; // skip ops not valid in current lifecycle state
            }
            if apply_op(&mut s, op) {
                if let Some(next) = next_lifecycle {
                    lifecycle = next;
                }
                if !initialized {
                    initialized = true;
                    continue; // skip property checks on init transition
                }
                // Check all properties after each successful transition
                prop_assert!(threshold_bounded(&s),
                    "threshold_bounded violated after op {:?} (step {})", op, i);
                prop_assert!(approvals_bounded(&s),
                    "approvals_bounded violated after op {:?} (step {})", op, i);
            }
        }
    }
}
